        if "XAI_API_KEY" in line:
            key = line.strip().split("=", 1)[1]
            break

# Test model
models = ["grok-3", "grok-3-mini", "grok-3-fast", "grok-2-latest", "grok-beta"]
for model in models:
    data = json.dumps({"model": model, "messages": [{"role": "user", "content": "hi"}], "max_tokens": 3}).encode()
    req = urllib.request.Request("https://api.x.ai/v1/chat/completions", data=data, headers={"Authorization": f"Bearer {key}", "Content-Type": "application/json"})
    try:
        resp = urllib.request.urlopen(req, timeout=10)
        result = resp.read().decode()
        print(f"{model}: {result[:100]}")
    except Exception as e:
        print(f"{model}: {e}")
